__kernel void lud_diagonal(__global float *a, __local float *local_a, const int size, const int offset) {
    int i = get_global_id(0);
    int j, k;

    if (i >= BLOCK_SIZE) return;

    for (j = i; j < BLOCK_SIZE; j++) {
        float sum = 0.0f;
        for (k = 0; k < i; k++) {
            sum += local_a[i * BLOCK_SIZE + k] * local_a[k * BLOCK_SIZE + j];
        }
        local_a[i * BLOCK_SIZE + j] -= sum;
    }

    float diag = local_a[i * BLOCK_SIZE + i];
    float inv_diag = 1.0f / diag;

    for (j = i + 1; j < BLOCK_SIZE; j++) {
        float sum = 0.0f;
        for (k = 0; k < i; k++) {
            sum += local_a[j * BLOCK_SIZE + k] * local_a[k * BLOCK_SIZE + i];
        }
        local_a[j * BLOCK_SIZE + i] = (local_a[j * BLOCK_SIZE + i] - sum) * inv_diag;
    }

    if (i == 0) {
